import pipeline_parallel as pp

# 1) Partition balance: every rank gets a contiguous, near-equal share covering all layers
def check_partition(num_layers, world_size):
    ranges = [pp._partition_layers(num_layers, world_size, r) for r in range(world_size)]
    counts = [e - s for s, e in ranges]
    # contiguous & complete
    assert ranges[0][0] == 0 and ranges[-1][1] == num_layers, (ranges, num_layers)
    for r in range(1, world_size):
        assert ranges[r][0] == ranges[r-1][1], ranges
    # balanced: max-min <= 1
    assert max(counts) - min(counts) <= 1, (num_layers, world_size, counts)
    # every rank gets >=1 layer when num_layers>=world_size
    if num_layers >= world_size:
        assert min(counts) >= 1, (num_layers, world_size, counts)
    return counts

for ws in (1, 2):
    for n in (1, 2, 3, 4, 5, 8, 12, 16, 31, 32):
        c = check_partition(n, ws)
        print(f"layers={n:3d} ws={ws} -> {c}")
print("PARTITION OK")

# 2) AFAB schedule: simulate send/recv pairing across ranks to prove no deadlock
#    and correct gradient routing, mirroring the order in train_step_pipeline_afab.
def simulate(world_size, num_micro):
    events = []  # (step, kind, src, dst)
    # Forward phase
    for rank in range(world_size):
        for i in range(num_micro):
            if rank != 0:
                events.append(("F", "recv", rank-1, rank, i))
            if rank != world_size-1:
                events.append(("F", "send", rank, rank+1, i))
    # Backward phase
    for rank in range(world_size):
        for i in range(num_micro):
            if rank != world_size-1:
                events.append(("B", "recv", rank+1, rank, i))
            if rank != 0:
                events.append(("B", "send", rank, rank-1, i))
    # every send must have a matching recv with same (phase, link, microbatch)
    sends = {(ph, s, d, i) for ph, k, s, d, i in events if k == "send"}
    recvs = {(ph, s, d, i) for ph, k, s, d, i in events if k == "recv"}
    assert sends == recvs, (sends ^ recvs)
    return len(sends)

for ws in (1, 2):
    for nm in (1, 2, 4):
        n = simulate(ws, nm)
        print(f"ws={ws} micro={nm} matched_transfers={n}")
print("SCHEDULE OK")
